#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_LINE_LENGTH 1000
#define MAX_LINES 1000
#define MAX_NUMBERS 50

int compare(const void *a, const void *b) {
    int *line1 = *(int **)a;
    int *line2 = *(int **)b;
    int i = 0;
    while (line1[i] != -1 && line2[i] != -1) {
        if (line1[i] < line2[i]) return -1;
        if (line1[i] > line2[i]) return 1;
        i++;
    }
    if (line1[i] == -1 && line2[i] != -1) return -1;
    if (line1[i] != -1 && line2[i] == -1) return 1;
    return 0;
}

int main() {
    int N;
    scanf("%d", &N);
    int **lines = malloc(N * sizeof(int *));
    for (int i = 0; i < N; i++) {
        lines[i] = malloc(MAX_NUMBERS * sizeof(int));
        for (int j = 0; j < MAX_NUMBERS; j++) {
            scanf("%d", &lines[i][j]);
            if (lines[i][j] == -1) break;
        }
    }
    qsort(lines, N, sizeof(int *), compare);
    for (int i = 0; i < N; i++) {
        for (int j = 0; lines[i][j] != -1; j++) {
            printf("%d ", lines[i][j]);
        }
        printf("\n");
    }
    return 0;
}

